mapper.select:
select * from ygt_member_share_invite

    and ygt_msi_campaign_id = #{campaignId}
    and ygt_msi_wecom_group_id = #{wecomGroupId}
    and ygt_msi_status = #{status}

order by ygt_member_share_invite_id desc
limit #{offset}, #{limit}

mapper.update:
update ygt_member_share_invite
ygt_msi_status = #{ygtMsiStatus}, ygt_msi_update_time = now()
where ygt_member_share_invite_id = #{ygtMemberShareInviteId}
